"use client";

import React, { useState, useEffect } from 'react';
import { MessageCircle } from 'lucide-react';
import { WHATSAPP_LINK } from '@/lib/constants';

export const WhatsAppBtn: React.FC = () => {
    const [isVisible, setIsVisible] = useState(false);

    useEffect(() => {
        const handleScroll = () => {
            // Mostrar botão a partir de 300px de scroll
            setIsVisible(window.scrollY > 300);
        };

        window.addEventListener('scroll', handleScroll, { passive: true });
        handleScroll(); // Checar estado inicial

        return () => window.removeEventListener('scroll', handleScroll);
    }, []);

    return (
        <a
            href={WHATSAPP_LINK}
            target="_blank"
            className={`fixed bottom-6 md:bottom-10 right-6 md:right-10 w-14 md:w-16 h-14 md:h-16 flex items-center justify-center rounded-full bg-gradient-to-tr from-green-600 to-green-400 transition-all duration-500 z-50 group shadow-lg ${isVisible ? 'opacity-100 translate-y-0 scale-100' : 'opacity-0 translate-y-10 scale-90 pointer-events-none'
                } hover:scale-110 hover:-translate-y-2 hover:shadow-[0_0_40px_rgba(74,222,128,0.5)]`}
            aria-label="Fale conosco no WhatsApp"
        >
            <div className="absolute inset-0 rounded-full border border-white/40 group-hover:border-white transition-colors"></div>
            <div className="absolute -inset-2 bg-green-500/20 rounded-full blur-xl group-hover:bg-green-400/30 transition-colors"></div>
            <MessageCircle size={28} className="text-white relative z-10" strokeWidth={2} />
        </a>
    );
};
